    color: rgb(4, 20, 29);
    background-color: rgb(255, 255, 255);
}

/* AFTER — gold accent button matching auth primary-button style */
.save-bttn{
    display: inline-flex;
    justify-content: center;
    align-items: center;
    padding: 10px 24px;
    border-radius: 8px;
